test_patch:
diff --git a/App/Layers/W1/Tests/ERM/ERMIntercompanyIII.Codeunit.al b/App/Layers/W1/Tests/ERM/ERMIntercompanyIII.Codeunit.al
index 0480aea9fa6..cf00000001 100644
--- a/App/Layers/W1/Tests/ERM/ERMIntercompanyIII.Codeunit.al
+++ b/App/Layers/W1/Tests/ERM/ERMIntercompanyIII.Codeunit.al
@@ -3408,6 +3408,43 @@ codeunit 134154 "ERM Intercompany III"
         Assert.AreEqual(300, SalesLine."Line Amount", 'When a sales order with a discount amount and prices including VAT is received from intercompany, the line amount should be preserved');
     end;

+    [Test]
+    procedure ICNavigateFromSalesCreditMemoLine()
+    var
+        Customer: Record Customer;
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        ICOutboxTransactions: TestPage "IC Outbox Transactions";
+        PostedSalesCreditMemo: TestPage "Posted Sales Credit Memo";
+    begin
+        // [SCENARIO 574577] "Unable to navigate to the related document" error message if you use Go to Document from the Intercompany Outbox Transactions for a Credit Memo.
+        Initialize();
+        LibraryApplicationArea.EnableEssentialSetup();
+        CleanupIC(false, true, true, false);
+        CreateCustomerWithICPartner(Customer);
+
+        // [GIVEN] A posted sales credit memo to an IC customer
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::"Credit Memo", Customer."No.");
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, LibraryInventory.CreateItemNo(), 1);
+        LibrarySales.PostSalesDocument(SalesHeader, true, true);
+
+        // [GIVEN] The posted sales credit memo IC transaction should be on the Outbox
+        ICOutboxTransactions.OpenEdit();
+
+        // [WHEN] Navigating from Outbox for this transaction
+        PostedSalesCreditMemo.Trap();
+        ICOutboxTransactions.GoToDocument.Invoke();
+
+        // [THEN] It should open the Posted Sales Credit Memo
+        PostedSalesCreditMemo."Pre-Assigned No.".AssertEquals(SalesHeader."No.");
+
+        // [WHEN] Document No. is empty
+        SalesHeader."No." := '';
+        ICOutboxTransactions.GoToDocument.Invoke();
+
+        // Cleanup
+        CleanupIC(false, true, true, false);
+    end;
+
     local procedure Initialize()
     var
         ICSetup: Record "IC Setup";

patch:
diff --git a/App/Layers/W1/BaseApp/Finance/Intercompany/ICNavigation.Codeunit.al b/App/Layers/W1/BaseApp/Finance/Intercompany/ICNavigation.Codeunit.al
index 92bf43b1d84..cf00000001 100644
--- a/App/Layers/W1/BaseApp/Finance/Intercompany/ICNavigation.Codeunit.al
+++ b/App/Layers/W1/BaseApp/Finance/Intercompany/ICNavigation.Codeunit.al
@@ -56,6 +56,20 @@ codeunit 437 "IC Navigation"
         exit(true);
     end;

+    local procedure NavigateToSalesCreditMemo(DocumentNo: Code[20]): Boolean
+    var
+        SalesCrMemoHeader: Record "Sales Cr.Memo Header";
+        PostedSalesCreditMemo: Page "Posted Sales Credit Memo";
+    begin
+        // An IC Transaction of type Sales Credit Memo can only be sent when posted.
+        if (DocumentNo = '') or not SalesCrMemoHeader.Get(DocumentNo) then
+            exit(false);
+        // The related document is a Posted Sales Credit Memo.
+        PostedSalesCreditMemo.SetRecord(SalesCrMemoHeader);
+        PostedSalesCreditMemo.Run();
+        exit(true);
+    end;
+
     local procedure NavigateToSalesInvoice(DocumentNo: Code[20]; ICPartnerCode: Code[20]): Boolean
     var
         Customer: Record Customer;
@@ -120,6 +134,8 @@ codeunit 437 "IC Navigation"
                 exit(NavigateToSalesOrderDocument(DocumentNo, ICDirectionType, ICPartnerCode));
             DocumentType::Invoice:
                 exit(NavigateToSalesInvoice(DocumentNo));
+            DocumentType::"Credit Memo":
+                exit(NavigateToSalesCreditMemo(DocumentNo));
             else begin
                 ShouldNavigateToDoc := false;
                 OnNavigateToSalesDocumentOnAfterCheckDocumentType(DocumentNo, ICDirectionType, ICPartnerCode, DocumentType, ShouldNavigateToDoc);

