+        Assert.AreNotEqual(0, VATEntry.Base, 'VAT Base should not be 0 for 50% Non-Deductible VAT.');
+        Assert.AreNotEqual(0, VATEntry.Amount, 'VAT Amount should not be 0 for 50% Non-Deductible VAT.');
     end;

     local procedure Initialize()
